package com.wwh.home.center.service.impl;import com.wwh.home.center.dao.mapper.PcDeviceMapper;import com.wwh.home.center.model.entity.PcDevice;import com.wwh.home.center.service.PcDeviceService;import org.springframework.beans.factory.annotation.Autowired;import org.springframework.stereotype.Service;import java.util.List;@Servicepublic class PcDeviceServiceImpl implements PcDeviceService {        @Autowired    private PcDeviceMapper pcDeviceMapper;        @Override    public List<PcDevice> getAllDevices() {        return pcDeviceMapper.selectList(null);    }} 